challenge_result.investigation_instruction:
{
  "plans": [
    {
      "hypothesis_id": "h1",
      "hypothesis_statement": "The Home Subscriber Server (HSS/pyhss) has exited, causing a complete failure of the IMS network. As the central database for subscriber authentication, its absence prevents UEs from performing IMS registration, making it impossible to establish VoNR calls, which explains the collapse in SIP dialogs, dedicated bearers, and user-plane traffic.",
      "primary_suspect_nf": "pyhss",
      "probes": [
        {
          "tool": "check_process_listeners",
          "args_hint": "container='pyhss'",
          "expected_if_hypothesis_holds": "Empty result, or no process listening on the Diameter port (3868). This confirms the process is down or unresponsive.",
          "falsifying_observation": "A process is actively listening on TCP/SCTP port 3868. This would indicate the HSS process is running and bound to its service port, contradicting the 'exited' hypothesis."
        },
        {
          "tool": "get_nf_metrics",
          "args_hint": "container='icscf', counters=['ims_icscf_uar_timeouts']",
          "expected_if_hypothesis_holds": "The 'ims_icscf_uar_timeouts' counter will be elevated and likely increasing, as the I-CSCF's User-Authorization-Requests (UARs) to the HSS will be failing.",
          "falsifying_observation": "The 'ims_icscf_uar_timeouts' counter is zero or not increasing. This implies the I-CSCF is either not attempting to contact the HSS or is receiving successful or error responses, both of which mean the HSS is reachable."
        },
        {
          "tool": "get_nf_metrics",
          "args_hint": "container='scscf', counters=['ims_registrar_scscf_sar_timeouts']",
          "expected_if_hypothesis_holds": "The 'ims_registrar_scscf_sar_timeouts' counter will be elevated and likely increasing, as the S-CSCF's Server-Assignment-Requests (SARs) to the HSS will be failing.",
          "falsifying_observation": "The 'ims_registrar_scscf_sar_timeouts' counter is zero or not increasing. This provides triangulation; if the S-CSCF can communicate with the HSS, the HSS has not exited."
        }
      ],
      "notes": "The plan focuses on verifying the 'exited' state of the HSS from multiple perspectives. Probe 1 checks for process-level network presence. Probes 2 and 3 check for the expected timeout failures from the two primary clients of the HSS (I-CSCF and S-CSCF) as defined in the 'ims_registration' flow (steps 4 and 7). If the clients are not seeing timeouts, the HSS cannot be down."
    }
  ]
}

